@import url('https://fonts.googleapis.com/css2?family=Inter:wght@700;800&family=Newsreader:ital,wght@0,400;0,600;1,400&family=Space+Grotesk:wght@400;500;600&display=swap');

/*
 * DDx token system — lever/load/fulcrum palette.
 *
 * Accent lever: #3B5B7A ≈ HSL(210, 36%, 35%). Hextra synthesizes primary
 * tints/shades from --primary-hue/saturation/lightness, re-tinting links,
 * accents, and focus rings to the DDx lever color.
 */

:root {
  /* Primary scale — drives Hextra's link/accent/focus utilities. */
  --primary-hue: 210deg;
  --primary-saturation: 36%;
  --primary-lightness: 35%;

  /* Lever/load/fulcrum accent tokens. */
  --ddx-accent-lever:   #3B5B7A;
  --ddx-accent-load:    #5A85B0;
  --ddx-accent-fulcrum: #2A3F56;
  --ddx-accent-brass:   #9A6A2F;

  /* Background tokens. */
  --ddx-bg-canvas:  #F7F1E7;
  --ddx-bg-surface: #FFFDF8;

  /* Foreground tokens. */
  --ddx-fg-ink:   #17130F;
  --ddx-fg-muted: #675F54;

  /* Border token. */
  --ddx-border-line: #D9CFC0;
}

.dark {
  /* Lift lightness in dark mode so links remain legible on dark backgrounds. */
  --primary-lightness: 55%;

  --ddx-bg-canvas:  #0F1117;
  --ddx-bg-surface: #1A1E2A;

  --ddx-fg-ink:   #E8EAF0;
  --ddx-fg-muted: #9CA3AF;

  --ddx-border-line: #2D3340;
  --ddx-accent-brass: #C79B5B;
}

body.ddx-editorial-home {
  margin: 0;
  min-height: 100vh;
  background:
    linear-gradient(180deg, rgba(255, 253, 248, 0.92), rgba(247, 241, 231, 0.98)),
    var(--ddx-bg-canvas);
  color: var(--ddx-fg-ink);
  font-family: "Space Grotesk", ui-sans-serif, system-ui, sans-serif;
  letter-spacing: 0;
}

.ddx-home-nav {
  position: fixed;
  inset: 0 0 auto;
  z-index: 20;
  height: 64px;
  border-bottom: 1px solid color-mix(in srgb, var(--ddx-border-line) 82%, transparent);
  background: color-mix(in srgb, var(--ddx-bg-canvas) 92%, transparent);
  backdrop-filter: blur(14px);
}

.ddx-home-nav__inner {
  display: flex;
  align-items: center;
  justify-content: space-between;
  width: min(1120px, calc(100% - 32px));
  height: 64px;
  margin: 0 auto;
}

.ddx-home-logo,
.ddx-home-footer__mark {
  color: var(--ddx-fg-ink);
  font-family: "Space Grotesk", ui-monospace, SFMono-Regular, Menlo, monospace;
  font-size: 15px;
  font-weight: 600;
  letter-spacing: 0;
  text-decoration: none;
  text-transform: uppercase;
}

.ddx-home-nav__links {
  display: flex;
  gap: 22px;
}

.ddx-home-nav__links a,
.ddx-home-actions a {
  color: var(--ddx-fg-ink);
  font-size: 14px;
  font-weight: 600;
  text-decoration: none;
}

.ddx-home-nav__links a {
  color: var(--ddx-fg-muted);
}

.ddx-home-nav__links a:hover,
.ddx-home-actions a:hover {
  color: var(--ddx-accent-lever);
}

.ddx-home-main {
  width: min(1120px, calc(100% - 32px));
  margin: 0 auto;
  padding: 128px 0 42px;
}

.ddx-home-hero {
  display: grid;
  grid-template-columns: minmax(0, 1.1fr) minmax(260px, 0.9fr);
  gap: 54px;
  align-items: end;
  min-height: calc(100vh - 154px);
}

.ddx-home-kicker,
.ddx-home-card__number,
.ddx-home-footer {
  font-family: "Space Grotesk", ui-monospace, SFMono-Regular, Menlo, monospace;
}

.ddx-home-kicker {
  margin: 0 0 18px;
  color: var(--ddx-accent-brass);
  font-size: 12px;
  font-weight: 600;
  letter-spacing: 0;
  text-transform: uppercase;
}

.ddx-home-title {
  max-width: 880px;
  margin: 0;
  color: var(--ddx-fg-ink);
  font-family: "Inter", ui-sans-serif, system-ui, sans-serif;
  font-size: clamp(46px, 7vw, 64px);
  font-weight: 800;
  line-height: 0.96;
  letter-spacing: 0;
}

.ddx-home-prose {
  max-width: 670px;
  margin: 30px 0 0;
  color: var(--ddx-fg-muted);
  font-family: "Newsreader", Georgia, serif;
  font-size: 18px;
  line-height: 1.62;
}

.ddx-home-actions {
  display: flex;
  flex-wrap: wrap;
  gap: 20px;
  margin-top: 34px;
}

.ddx-home-action-primary {
  border-bottom: 2px solid var(--ddx-accent-brass);
}

.ddx-home-quote {
  margin: 0;
  padding: 0 0 0 24px;
  border-left: 2px solid var(--ddx-accent-brass);
  color: var(--ddx-fg-ink);
  font-family: "Newsreader", Georgia, serif;
  font-size: 25px;
  line-height: 1.28;
}

.ddx-home-quote cite {
  display: block;
  margin-top: 18px;
  color: var(--ddx-fg-muted);
  font-family: "Space Grotesk", ui-sans-serif, system-ui, sans-serif;
  font-size: 12px;
  font-style: normal;
  font-weight: 600;
  text-transform: uppercase;
}

.ddx-home-principles {
  padding: 64px 0 28px;
}

.ddx-home-section-label {
  margin: 0 0 20px;
  color: var(--ddx-fg-muted);
  font-size: 13px;
  font-weight: 600;
}

.ddx-home-grid {
  display: grid;
  grid-template-columns: repeat(3, minmax(0, 1fr));
  gap: 14px;
}

.ddx-home-card {
  aspect-ratio: 1 / 1;
  display: flex;
  flex-direction: column;
  justify-content: space-between;
  padding: 24px;
  border: 1px solid var(--ddx-border-line);
  background: color-mix(in srgb, var(--ddx-bg-surface) 86%, transparent);
}

.ddx-home-card__number {
  color: var(--ddx-accent-lever);
  font-size: 12px;
  font-weight: 600;
}

.ddx-home-card:nth-child(2) .ddx-home-card__number,
.ddx-home-card:nth-child(5) .ddx-home-card__number {
  color: var(--ddx-accent-load);
}

.ddx-home-card:nth-child(3) .ddx-home-card__number,
.ddx-home-card:nth-child(6) .ddx-home-card__number {
  color: var(--ddx-accent-fulcrum);
}

.ddx-home-card h2 {
  margin: 0 0 12px;
  color: var(--ddx-fg-ink);
  font-size: 22px;
  line-height: 1.08;
}

.ddx-home-card p {
  margin: 0;
  color: var(--ddx-fg-muted);
  font-family: "Newsreader", Georgia, serif;
  font-size: 17px;
  line-height: 1.42;
}

.ddx-home-footer {
  display: flex;
  justify-content: space-between;
  gap: 24px;
  padding-top: 28px;
  border-top: 1px solid var(--ddx-border-line);
  color: var(--ddx-fg-muted);
  font-size: 12px;
}

@media (max-width: 820px) {
  .ddx-home-main {
    padding-top: 104px;
  }

  .ddx-home-hero {
    grid-template-columns: 1fr;
    gap: 36px;
    min-height: auto;
  }

  .ddx-home-title {
    font-size: 46px;
  }

  .ddx-home-grid {
    grid-template-columns: 1fr;
  }

  .ddx-home-card {
    aspect-ratio: auto;
    min-height: 220px;
  }
}

@media (max-width: 520px) {
  .ddx-home-nav__inner,
  .ddx-home-main {
    width: min(100% - 24px, 1120px);
  }

  .ddx-home-nav__links {
    gap: 14px;
  }

  .ddx-home-title {
    font-size: 40px;
  }

  .ddx-home-footer {
    flex-direction: column;
  }
}

